#include <bits/stdc++.h>
using namespace std;
struct ListNode {
    int val;
    ListNode *next;
    ListNode(int x) : val(x), next(NULL) {}
};
ListNode* createLinkedList(vector<int>& lst) {
    ListNode* dummy = new ListNode(0);
    ListNode* curr = dummy;
    for (int val : lst) {
        curr->next = new ListNode(val);
        curr = curr->next;
    }
    return dummy->next;
}
ListNode* addTwoNumbers(ListNode* l1, ListNode* l2) {
    ListNode* dummy = new ListNode(0);
    ListNode* curr = dummy;
    int carry = 0;
    while (l1 || l2 || carry) {
        int x = (l1 != NULL) ? l1->val : 0;
        int y = (l2 != NULL) ? l2->val : 0;
        int sum = carry + x + y;
        carry = sum / 10;
        curr->next = new ListNode(sum % 10);
        curr = curr->next;
        if (l1) l1 = l1->next;
        if (l2) l2 = l2->next;
    }
    return dummy->next;
}
void printLinkedList(ListNode* node) {
    while (node) {
        cout << node->val << ' ';
        node = node->next;
    }
    cout << endl;
}
int main() {
    int n1;
    cin >> n1;
    vector<int> l1(n1);
    for (int i = 0; i < n1; i++) cin >> l1[i];
    int n2;
    cin >> n2;
    vector<int> l2(n2);
    for (int i = 0; i < n2; i++) cin >> l2[i];
    ListNode* l1List = createLinkedList(l1);
    ListNode* l2List = createLinkedList(l2);
    ListNode* result = addTwoNumbers(l1List, l2List);
    printLinkedList(result);
    return 0;
}
